mapper.select:
-- 영업 사이트 목록을 검색 조건에 따라 조회한다. SELECT o.opportunity_id, d.code AS department_code, d.name AS department_name, o.customer_name, o.project_name, o.expected_order_period, o.expected_delivery_period, o.project_amount, o.owner_name, o.status, ps.probability, ps.name AS probability_stage_name FROM opportunities o INNER JOIN departments d ON d.department_id = o.department_id INNER JOIN probability_stages ps ON ps.probability_stage_id = o.probability_stage_id
AND d.code IN
#{accessDepartmentCode}
AND 1 = 0
AND d.code = #{departmentCode}
AND o.status = #{status}
ORDER BY o.created_at DESC, o.opportunity_id DESC
